package com.zaritcare.data.mocks.activity

import com.zaritcare.data.room.activity.ActivityEntity
import javax.inject.Inject

class ActivityDaoMock @Inject constructor() {
    private val photoBurstBalloon: String = ""
    private val photoMeditation: String = ""
    private val photoExercise: String = ""
    private val photoGlass: String = ""

    private val activities: MutableList<ActivityMock> = mutableListOf(
        ActivityMock(
            id = 1,
            image = photoBurstBalloon,
            frontPage = "",
            title = "Reventar un globo",
            description = "Libera el estrés presionado el globo hasta hacerlo estallar.",
            authorQuote = "No es el estrés lo que nos mata, sino cómo reaccionamos ante él.",
            quote = "Hans Selye",
            action = "Revienta el globo"
        ),
        ActivityMock(
            id = 2,
            frontPage = "",
            image = photoMeditation,
            title = "Meditación",
            description = "La meditación es una practica que reduce la ansiedad, el estrés, y los síntomas de la depresión. Te ayudan a sentirte tranquilo y en paz.",
            authorQuote = "Nada es permanente en este mundo, ni siquiera nuestros problemas.",
            quote = "Charlie Chaplin",
            action = "Concentrese en su respiracion,  Inhale Exhale. Siga su respiracion durante varios minutos."
        ),
        ActivityMock(
            id = 3,
            frontPage = "",
            image = photoExercise,
            title = "Realizar ejercicio",
            description = "Caminar aumenta la resistencia, disminuye la depresión, el estrés, el insomnio y muchos otros problemas emocionales.",
            authorQuote = "Mantener nuestro cuerpo con buena salud es un deber. De lo contrario no seremos capaces de mantener nuestras mentes fuertes y claras.",
            quote = "Buda",
            action = "Concentrese en su respiracion,  Inhale Exhale. Siga su respiracion durante varios minutos."
        )
    )

    fun get(): MutableList<ActivityMock> = activities
    fun get(id: Int): ActivityMock? = activities.find { activity -> activity.id == id }
    fun insert(activity: ActivityMock) = activities.add(activity)
    fun count() = activities.size
    fun update(newActivity: ActivityMock) {
        val index: Int = activities.indexOfFirst { activity -> activity.id == newActivity.id }
        if (index != -1) activities[index] = newActivity
    }
    fun delete(id: Int) {
        val index = activities.indexOfFirst { activity -> activity.id == id }
        if (index != -1) activities.removeAt(index)
    }
}